import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Registration from './Registration';

function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showRegisterModal, setShowRegisterModal] = useState(false);
  const navigate = useNavigate();

  // Show Register modal only first time
  useEffect(() => {
    const alreadyShown = localStorage.getItem("registerShown");
    if (!alreadyShown) {
      setShowRegisterModal(true);
      localStorage.setItem("registerShown", "true");
    }
  }, []);

  const handleLogin = (e) => {
    e.preventDefault();
    console.log('Login Data:', { email, password });
    alert('Login successful! Redirecting to dashboard...');
    navigate('/dashboard');
  };

  // --- your styles (unchanged) ---
  const styles = { /* keep exactly what you wrote above */ };

  const userIcon = { icon: '👤' };
  const orbs = [
    { size: '120px', top: '10%', left: '10%', animationDelay: '0s' },
    { size: '80px', top: '70%', left: '80%', animationDelay: '2s' },
    { size: '100px', top: '20%', left: '85%', animationDelay: '4s' },
    { size: '90px', top: '80%', left: '15%', animationDelay: '1s' },
  ];
  const animationStyles = `
    @keyframes float {
      0%, 100% { transform: translateY(0px) rotate(0deg); }
      50% { transform: translateY(-20px) rotate(180deg); }
    }
  `;

  return (
    <>
      <style>{animationStyles}</style>
      <div style={styles.loginContainer}>
        <div style={styles.backgroundAnimation} />

        <div style={styles.loginCard}>
          {/* ---- LEFT Login Form ---- */}
          <div style={styles.loginFormSection}>
            <h2 style={styles.heading}>FLOW TRACK</h2>
            <form onSubmit={handleLogin} style={styles.form}>
              <div style={styles.inputGroup}>
                <div style={styles.inputIcon}>@</div>
                <input
                  type="email"
                  placeholder="Email Address"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  style={styles.input}
                />
              </div>

              <div style={styles.inputGroup}>
                <div style={styles.inputIcon}>#</div>
                <input
                  type="password"
                  placeholder="Password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  style={styles.input}
                />
              </div>

              <button type="submit" style={styles.button}>Sign In</button>
            </form>

            {/* Register trigger */}
            <p style={styles.registerLink}>
              Don't have an account?{" "}
              <button
                style={{ ...styles.link, background: "none", border: "none", cursor: "pointer" }}
                onClick={() => setShowRegisterModal(true)}
              >
                Get Started
              </button>
            </p>
          </div>

          {/* ---- RIGHT Graphic ---- */}
          <div style={styles.graphicSection}>
            <div style={styles.floatingOrbs}>
              {orbs.map((orb, i) => (
                <div key={i} style={{ ...styles.orb, ...orb }} />
              ))}
            </div>
            <div style={styles.userIconContainer}>
              <div style={styles.userIcon}>{userIcon.icon}</div>
              <h3 style={styles.userText}>Welcome Back</h3>
              <p style={styles.userDescription}>
                Sign in to access your projects, collaborate with your team, 
                and continue tracking your progress seamlessly.
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* ---- Registration Modal ---- */}
      {showRegisterModal && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <button style={closeBtn} onClick={() => setShowRegisterModal(false)}>×</button>
            <Registration />
          </div>
        </div>
      )}
    </>
  );
}

// Simple modal styles
const modalOverlay = {
  position: "fixed", top: 0, left: 0, right: 0, bottom: 0,
  background: "rgba(0,0,0,0.5)",
  display: "flex", justifyContent: "center", alignItems: "center",
  zIndex: 1000
};
const modalContent = {
  background: "#fff", padding: "20px", borderRadius: "12px",
  width: "500px", maxWidth: "90%", position: "relative"
};
const closeBtn = {
  position: "absolute", top: "10px", right: "10px",
  background: "none", border: "none", fontSize: "20px", cursor: "pointer"
};

export default LoginPage;
